import { CellData, GridPosition, SuperTileType, posKey } from './Types';

/**
 * BFS‑based resolver for connected same‑colour tile groups.
 *
 * Pure domain logic — no Cocos dependencies.
 * Treats super‑tiles as opaque: they are never part of a colour group.
 */
export class MatchResolver {

    private static readonly DIRS: ReadonlyArray<GridPosition> = [
        { row: -1, col:  0 },
        { row:  1, col:  0 },
        { row:  0, col: -1 },
        { row:  0, col:  1 },
    ];

    // ── Public API ────────────────────────────────────────

    /**
     * Return every position connected to (startRow, startCol) by colour.
     * Super‑tiles are excluded (they activate via a different path).
     */
    public static findGroup(
        grid: ReadonlyArray<ReadonlyArray<CellData | null>>,
        startRow: number,
        startCol: number,
    ): GridPosition[] {
        const rows = grid.length;
        const cols = grid[0].length;
        const cell = grid[startRow]?.[startCol];

        if (!cell || cell.superType !== SuperTileType.None) {
            return cell ? [{ row: startRow, col: startCol }] : [];
        }

        const target  = cell.color;
        const visited = new Set<string>();
        const group: GridPosition[]  = [];
        const queue: GridPosition[]  = [{ row: startRow, col: startCol }];
        visited.add(posKey(startRow, startCol));

        while (queue.length > 0) {
            const cur = queue.shift()!;
            group.push(cur);

            for (const d of this.DIRS) {
                const nr = cur.row + d.row;
                const nc = cur.col + d.col;
                if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;

                const k = posKey(nr, nc);
                if (visited.has(k)) continue;

                const n = grid[nr][nc];
                if (n && n.superType === SuperTileType.None && n.color === target) {
                    visited.add(k);
                    queue.push({ row: nr, col: nc });
                }
            }
        }
        return group;
    }

    /**
     * `true` when at least one valid group of ≥ minSize exists
     * **or** a clickable super‑tile is on the board.
     */
    public static hasAnyValidGroup(
        grid: ReadonlyArray<ReadonlyArray<CellData | null>>,
        minGroupSize: number,
    ): boolean {
        const rows = grid.length;
        const cols = grid[0].length;
        const visited = new Set<string>();

        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < cols; c++) {
                const cell = grid[r][c];
                if (!cell) continue;
                if (cell.superType !== SuperTileType.None) return true;

                const k = posKey(r, c);
                if (visited.has(k)) continue;

                if (this.bfsCount(grid, r, c, visited) >= minGroupSize) return true;
            }
        }
        return false;
    }

    // ── Internal BFS (counts only, avoids allocation) ─────

    private static bfsCount(
        grid: ReadonlyArray<ReadonlyArray<CellData | null>>,
        startRow: number,
        startCol: number,
        visited: Set<string>,
    ): number {
        const rows = grid.length;
        const cols = grid[0].length;
        const cell = grid[startRow][startCol];
        if (!cell || cell.superType !== SuperTileType.None) return 0;

        const target = cell.color;
        const queue: GridPosition[] = [{ row: startRow, col: startCol }];
        visited.add(posKey(startRow, startCol));
        let count = 0;

        while (queue.length > 0) {
            const cur = queue.shift()!;
            count++;

            for (const d of this.DIRS) {
                const nr = cur.row + d.row;
                const nc = cur.col + d.col;
                if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;

                const k = posKey(nr, nc);
                if (visited.has(k)) continue;

                const n = grid[nr][nc];
                if (n && n.superType === SuperTileType.None && n.color === target) {
                    visited.add(k);
                    queue.push({ row: nr, col: nc });
                }
            }
        }
        return count;
    }
}
